function inUsBounds(lat: number, lng: number): boolean {
  return lat >= 24 && lat <= 50 && lng >= -127 && lng <= -66;
}

function cityStateKey(city: string, state: string): string {
  return `${city.trim()},${state.trim().toUpperCase()}`;
}

export function resolvePropertyCoordinate(property: Pick<PulseProperty, "city" | "state" | "lat" | "lng">): ResolvedCoordinate {
  const { lat, lng } = property;

  // Happy path: valid US coordinate as provided.
  if (inUsBounds(lat, lng)) {
    return { lat, lng, source: "provided" };
  }

  // Common data issue: lat/lng swapped during ingest.
  if (inUsBounds(lng, lat)) {
    return { lat: lng, lng: lat, source: "swapped" };
  }

  // Last-resort deterministic fallback by city/state centroid.
  const fallback = CITY_STATE_COORDINATES[cityStateKey(property.city, property.state)];
  if (fallback) {
    return { ...fallback, source: "fallback" };
  }

  // Stable default: geographic center of CONUS.
  return { lat: 39.8283, lng: -98.5795, source: "fallback" };
}

export function resolveHqCoordinate(hq: Pick<CustomerHQ, "city" | "state" | "lat" | "lng">): ResolvedCoordinate {
  if (inUsBounds(hq.lat, hq.lng)) {
    return { lat: hq.lat, lng: hq.lng, source: "provided" };
  }
  if (inUsBounds(hq.lng, hq.lat)) {
    return { lat: hq.lng, lng: hq.lat, source: "swapped" };
  }
  const fallback = CITY_STATE_COORDINATES[cityStateKey(hq.city, hq.state)];
  if (fallback) {
    return { ...fallback, source: "fallback" };
  }
  return { lat: 39.8283, lng: -98.5795, source: "fallback" };
}
